    private fun extractSharedContent(intent: Intent): SharedContent {
        val action = intent.action
        if (action != Intent.ACTION_SEND && action != Intent.ACTION_SEND_MULTIPLE) {
            return SharedContent.Empty
        }

        val uris = LinkedHashSet<Uri>()
        val texts = LinkedHashSet<String>()

        fun addText(s: String?) {
            val t = s?.trim().orEmpty()
            if (t.isNotEmpty()) texts.add(t)
        }

        fun addUri(u: Uri?) {
            if (u != null) uris.add(u)
        }

        addText(intent.getStringExtra(Intent.EXTRA_TEXT))
        addText(intent.getStringExtra(Intent.EXTRA_SUBJECT))

        if (intent.hasExtra(Intent.EXTRA_STREAM)) {
            @Suppress("DEPRECATION")
            if (action == Intent.ACTION_SEND_MULTIPLE) {
                val list = intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)
                list?.forEach { addUri(it) }
            } else {
                @Suppress("DEPRECATION")
                addUri(intent.getParcelableExtra(Intent.EXTRA_STREAM))
            }
        }

        intent.clipData?.let { clip ->
            for (i in 0 until clip.itemCount) {
                val item = clip.getItemAt(i)
                addText(item.text?.toString())
                addUri(item.uri)
                addUri(item.intent?.data)
            }
        }

        val urls = LinkedHashSet<String>()
        val otherText = LinkedHashSet<String>()

        for (t in texts) {
            val parts = t.split('\n', ' ', '\t', ',', ';', '(', ')', '[', ']', '{', '}', '<', '>', '"', '\'')
                .map { it.trim() }
                .filter { it.isNotEmpty() }

            var foundUrl = false
            for (p in parts) {
                val cleaned = p.trim().trimEnd('.', ',', ';', ':', '!', '?')
                if (isLikelyUrl(cleaned)) {
                    urls.add(normalizeUrl(cleaned))
                    foundUrl = true
                }
            }
            if (!foundUrl) otherText.add(t)
        }

        val imageUris = uris.filter { isImageUri(contentResolver, it) }.toSet()
        val otherUris = uris - imageUris

        if (urls.isEmpty() && imageUris.isEmpty() && otherText.isEmpty() && otherUris.isEmpty()) {
            return SharedContent.Empty
        }

        return SharedContent.Payload(
            urls = urls.toList(),
            imageUris = imageUris.toList(),
            otherUris = otherUris.toList(),
            text = otherText.toList()
        )
    }

    private fun processSharedContent(content: SharedContent) {
        when (content) {
