    private fun isLikelyUrl(s: String): Boolean {
        if (s.isBlank()) return false
        if (URLUtil.isNetworkUrl(s)) return true
        if (s.startsWith("www.", ignoreCase = true)) return true
        return false
    }

    private fun normalizeUrl(s: String): String {
        if (URLUtil.isNetworkUrl(s)) return s
        if (s.startsWith("www.", ignoreCase = true)) return "https://$s"
        return s
    }

    private fun isImageUri(resolver: ContentResolver, uri: Uri): Boolean {
        if (uri.scheme == ContentResolver.SCHEME_CONTENT) {
            val type = resolver.getType(uri)
            if (!type.isNullOrBlank()) return type.startsWith("image/")
        }
        val path = uri.toString().lowercase()
        return path.endsWith(".jpg") || path.endsWith(".jpeg") || path.endsWith(".png") || path.endsWith(".gif") || path.endsWith(".webp") || path.endsWith(".heic") || path.endsWith(".heif")
    }
